class Solution(object):
    def distinctPrimeFactors(self, nums):
        def prime_factors(n):
            factors = set()
            d = 2
            while d * d <= n:
                while n % d == 0:
                    factors.add(d)
                    n //= d
                d += 1
            if n > 1:
                factors.add(n)
            return factors
        all_factors = set()
        for num in nums:
            all_factors.update(prime_factors(num))
        return len(all_factors)
